// 피드백 저장
async function saveFeedback({station,direction,car,zone,hour,result,congestion}){
  try{
    await addDoc(collection(db,"feedbacks"),{
      station,direction,car,zone,hour,result,congestion,
      timestamp:serverTimestamp(),appVersion:"1.0.0",
    });
  }catch(e){console.error("피드백 저장 실패:",e);}
}

