// 피드백 불러와서 베이지안 보정값 계산
// prior: alpha=2, beta=5 (기본 확률 2/7 ≈ 28%)
async function loadFeedbackCorrection(station,direction,car,zone,hour){
  try{
    const slot=toSlot(hour,new Date().getMinutes());
    const q=query(
      collection(db,"feedbacks"),
      where("station","==",station),
      where("direction","==",direction),
      where("car","==",car),
      where("zone","==",zone),
    );
    const snap=await getDocs(q);
    let alpha=2,beta=5; // prior
    snap.forEach(doc=>{
      const d=doc.data();
      if(d.result==="sat") alpha++;
      else beta++;
    });
    const N=alpha+beta-7; // 실제 피드백 수
    const feedbackProb=alpha/(alpha+beta);
    const confidence=Math.max(0,1-Math.exp(-Math.max(0,N)/10));
    return{feedbackProb,confidence,count:N};
  }catch(e){return{feedbackProb:null,confidence:0,count:0};}
}

