// ── 노선별 유틸 함수 ───────────────────────────────────────
function getLineArr(lineNum,branch=false){
  if(lineNum===1) return LINE1;
  if(lineNum===3) return LINE3;
  if(lineNum===4) return LINE4;
  if(lineNum===5) return branch?LINE5H:LINE5;
  if(lineNum===6) return LINE6;
  if(lineNum===7) return LINE7;
  if(lineNum===8) return LINE8;
  return LINE2;
}
function getLineN(lineNum,branch=false){
  if(lineNum===1) return N1;
  if(lineNum===3) return N3;
  if(lineNum===4) return N4;
  if(lineNum===5) return branch?N5H:N5;
  if(lineNum===6) return N6;
  if(lineNum===7) return N7;
  if(lineNum===8) return N8;
  return N;
}

// 방향 계산 (노선 공통)
// 2호선: 순환선 → 내선/외선
// 3호선: 직선 → 상선(I)/하선(O)
function calcDir(from, to, lineNum=2){
  const LINE=getLineArr(lineNum);
  const LN=getLineN(lineNum);
  const fi=LINE.indexOf(from), ti=LINE.indexOf(to);
  if(fi===-1||ti===-1) return "I";
  if(lineNum===2){
    const fwd=(ti-fi+LN)%LN;
    return fwd<=LN/2?"I":"O";
  }
  // 직선 노선: from→to 방향이 배열 순서면 I(상선), 역방향이면 O(하선)
  return ti>fi?"I":"O";
}

function getNextSt(cur, d, lineNum=2){
  const LINE=getLineArr(lineNum);
  const LN=getLineN(lineNum);
  const i=LINE.indexOf(cur);
  if(i===-1) return null;
  if(lineNum===2){
    return LINE[d==="I"?(i+1)%LN:(i-1+LN)%LN];
  }
  // 직선 노선: 끝에서 null
  if(d==="I") return i<LN-1?LINE[i+1]:null;
  return i>0?LINE[i-1]:null;
}


