function toSlot(h,m){return`${String(h).padStart(2,"0")}:${m<30?"00":"30"}`;}

function getCong(st,d,h,m,lineNum=2){
  const slot=toSlot(h,m);
  const ctMap={1:CT1, 2:CT, 3:CT3, 4:CT4, 5:CT5, 6:CT6, 7:CT7, 8:CT8};
  const t=(ctMap[lineNum]||CT)[st];
  if(t){
    const dv=t[d]||t["I"]||t["O"];
    if(dv){
      if(dv[slot]!==undefined) return dv[slot];
      const keys=Object.keys(dv).sort(),sn=h*60+(m<30?0:30);
      let cl=keys[0],md=9999;
      for(const k of keys){const[kh,km]=k.split(":").map(Number),df=Math.abs(kh*60+km-sn);if(df<md){md=df;cl=k;}}
      return dv[cl];
    }
  }
  return CT["_d"][slot]??CT["_d"]["07:30"]??45;
}

// ── 칸/구역별 확률 계산 (zone 보정 포함) ─────────────────
// quickExitPenalty: 현재역 빠른하차 칸 = 자리경쟁 심함 → 패널티
// quickExitBonus: 다음역 빠른하차 칸 = 많이 내릴 예정 → 보너스
function calcZoneBonus(st,car,zone,nst?,d?){
  const doors=DOOR_DATA[st]||[];
  let bonus=0;
  for(const{door:[dc,dp],bonus:b} of doors){
    if(dc!==car) continue;
    const dist=Math.abs(dp-(zone+0.5));
    bonus+=b*Math.exp(-0.7*dist);
  }
  // 칸별 보정: 앞칸(1번)과 뒷칸(10번) 선호도 차이
  const carPenalty=car<=2||car>=9?0.05:car<=4||car>=7?0.02:0;

  // 빠른하차 보정
  let quickPenalty=0, quickBonus=0;
  const qe=QUICK_EXIT_DATA[st];
  if(qe){
    const quickCars=d==="I"?qe.I:qe.O;
    if(quickCars.includes(car)){
      // 현재역 빠른하차 칸: 자리 경쟁 심함 → 패널티 (-5%)
      quickPenalty=0.05;
    }
  }
  if(nst){
    const qeN=QUICK_EXIT_DATA[nst];
    if(qeN){
      const quickCarsN=d==="I"?qeN.I:qeN.O;
      if(quickCarsN.includes(car)){
        // 다음역 빠른하차 칸: 많이 내릴 예정 → 보너스 (+8%)
        quickBonus=0.08;
      }
    }
  }
  return{bonus:Math.min(bonus+quickBonus,0.20),penalty:carPenalty+quickPenalty};
}

function calcProb(st,nst,d,h,m,car=5,zone=2,lineNum=2){
  const C=getCong(st,d,h,m,lineNum);
  const Cn=nst?getCong(nst,d,h,m,lineNum):C;

  // 1. 좌석 점유율 (혼잡도 60% = 좌석 만석 기준)
  const seatOccupancy=Math.min(1, C/60);
  const emptySeatRate=Math.max(0, 1-seatOccupancy);

  // 2. 하차로 생기는 빈자리
  // - 현재역이 환승역: 이미 많이 내린 상태 → 현재 빈자리 보너스
  const isCurTransfer=TRANSFER.has(st);
  // - 다음역이 환승역: 거기서 많이 내릴 예정 → 하차 보너스
  const isNextTransfer=nst&&TRANSFER.has(nst);

  const rawAlightRate=Math.max(0, C-Cn)/100;
  const transferBonus=isNextTransfer?0.15:0;
  const curTransferBonus=isCurTransfer?0.08:0; // 현재역 환승 보너스
  const minAlight=C<=30?0.20:C<=60?0.10:0.05;
  const effectiveAlight=Math.max(rawAlightRate+transferBonus, minAlight*(C/100));

  // 3. 최종 확률
  let P=emptySeatRate*0.8 + Math.min(0.7,effectiveAlight)*(1-emptySeatRate*0.8);
  P=Math.min(0.95, P+curTransferBonus);

  // 4. 칸/구역 보정 (빠른하차 정보 포함)
  const{bonus,penalty}=calcZoneBonus(st,car,zone,nst,d);
  P=P*(1+bonus)*(1-penalty);
  const zoneDiff=(zone===1?0.03:zone===2?0:-0.02);
  P=Math.max(0.02,Math.min(0.95,P+zoneDiff));
  return Math.round(P*100);
}

function bestZone(st,nst,d,h,m,lineNum=2){
  let b={car:1,zone:1,prob:0},bn={car:1,zone:1,prob:0};
  for(let c=1;c<=10;c++)for(let z=1;z<=3;z++){
    const p=calcProb(st,nst,d,h,m,c,z,lineNum);
    if(p>b.prob)b={car:c,zone:z,prob:p};
    if(nst){const np=calcProb(nst,getNextSt(nst,d,lineNum),d,h,m,c,z,lineNum);if(np>bn.prob)bn={car:c,zone:z,prob:np};}
  }
  return{cur:b,next:nst?bn:null};
}

